export async function getServerSideProps({
  query
}) {
  const {
    id
  }
  = query;
  // ❌ No validation — passes raw input
  const res = await fetch(`https://api.yoursite.com/user?id=${id}`);
  const user = await res.json();
  return {
    props: {
      user
    }
  };
}

